 /**
  * [POST] /api/parser/submit-form
- * 작성 완료된 자재 데이터를 수신하여 올빌드 대시보드(프론트엔드)로 자동 리다이렉트합니다.
- */
-router.post('/parser/submit-form', (req, res) => {
+ * 작성 완료된 자재 데이터와 첨부파일(사진, 엑셀)을 수신하여 올빌드 대시보드(프론트엔드)로 자동 리다이렉트합니다.
+ */
+const templateUpload = upload.fields([
+    { name: 'photoFiles', maxCount: 5 },
+    { name: 'excelFile', maxCount: 1 }
+]);
+
+router.post('/parser/submit-form', templateUpload, (req, res) => {
     const { items } = req.body;
+    const fs = require('fs');
+    const path = require('path');

     if (!items) {
         return res.status(400).send('<h2>자재 데이터가 전송되지 않았습니다.</h2>');
@@ -616,8 +616,38 @@

-    console.log(`[API] 템플릿 폼 주문 수신 완료: ${items}`);
-
-    // 대시보드 사이트로 리다이렉트하며 쿼리 스트링으로 데이터를 실어 보냄
-    const redirectUrl = `http://localhost:5173/?source=direct-import&data=${encodeURIComponent(items)}`;
+    const savedFilesInfo = []; // DB 저장 및 대시보드 리다이렉트 전달용 정보 배열
+
+    try {
+        // 1. 사진 파일 업로드 및 물리 저장
+        if (req.files && req.files.photoFiles) {
+            req.files.photoFiles.forEach(file => {
+                // 고유한 한글 안 깨지는 파일명 보장을 위한 타임스탬프 결합
+                const uniqueName = `${Date.now()}_${file.originalname}`;
+                const savePath = path.join(__dirname, '../uploads', uniqueName);
+                fs.writeFileSync(savePath, file.buffer);
+                
+                const url = `http://localhost:5000/uploads/${uniqueName}`;
+                savedFilesInfo.push({ name: file.originalname, url: url, type: 'photo' });
+            });
+        }
+
+        // 2. 엑셀 파일 업로드 및 물리 저장
+        if (req.files && req.files.excelFile && req.files.excelFile[0]) {
+            const file = req.files.excelFile[0];
+            const uniqueName = `${Date.now()}_${file.originalname}`;
+            const savePath = path.join(__dirname, '../uploads', uniqueName);
+            fs.writeFileSync(savePath, file.buffer);
+            
+            const url = `http://localhost:5000/uploads/${uniqueName}`;
+            savedFilesInfo.push({ name: file.originalname, url: url, type: 'excel' });
+        }
+
+        console.log(`[API] 템플릿 주문서 정보 수신 성공! 자재 수: ${JSON.parse(items).length}개, 첨부파일 수: ${savedFilesInfo.length}개`);
+    } catch (err) {
+        console.error('[API 에러] 템플릿 첨부파일 저장 에러:', err);
+    }
+
+    // 대시보드 사이트로 리다이렉트하며 쿼리 스트링으로 자재 데이터 및 파일 보존 정보를 실어 보냄
+    const redirectUrl = `http://localhost:5173/?source=direct-import&data=${encodeURIComponent(items)}&files=${encodeURIComponent(JSON.stringify(savedFilesInfo))}`;
     return res.redirect(redirectUrl);
